h=A.w(c8,h,c8)
e=A.y("The team included several singers, musicians and composers, a choreographer, a writer, a designer, a 3d graphics artist and a software developer. \nI was selected as the developer for the project for my experience as an opera singer, guitarist and previous work on interactive environments and human computer interaction.",A.v(c8,c8,c8,c8,c8,c8,c8),c8,c8)
