d=A.w(c8,d,c8)
a=A.y("Development of an interactive opera incorporating live and virtual elements, along with an online co-creation environment to elicit public participation during collective immersive experiences.",A.v(c8,c8,c8,c8,c8,c8,c8),c8,c8)
a0=s.y
