d5=s.y
d6=A.w(e9,d5,e9)
d7=A.y("4. Preliminary evaluation",s.x,e9,e9)
d5=A.w(e9,d5,e9)
d8=A.y("Participants will be presented with the device to evaluate the functions and the usability of the prototype. A focus group will gather the perceptions of the participants about the device, the project and the process in general, along with perspectives for development. ",A.v(e9,e9,e9,e9,e9,e9,e9),e9,e9)
d9=s.y
e0=A.w(e9,d9,e9)
e1=A.y("5. Final evaluation",s.x,e9,e9)
d9=A.w(e9,d9,e9)
e2=A.y("A final prototype will be built from the insights gathered at a final group design session. Participants will be trained in the use of the final prototype and they will be asked to perform a set of internet navigation tasks with and without our assistive technology. Participants will evaluate the usability of the device and its impact on their user experience. The number of keystrokes, time to completion of task and number of tasks completed will be logged by the computer. \n",A.v(e9,e9,e9,e9,e9,e9,e9),e9,e9)
